class Solution {
    public int minimumSpeed(int n, float hour, int[] dist) {
        if (n > Math.ceil(hour)) return -1;
        int low = 1, high = 10000000, mid, speed;

        while (low <= high) {
            mid = low + (high - low) / 2;
            float time = 0;
            for (int i = 0; i < n; ++i) {
                time += Math.ceil(dist[i] * 1.0 / mid);
            }
            if (time <= hour) {
                speed = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return speed;
    }
}
```

